    { id: 'shaw-kpi-4', longTermGoal: 'The Shaw-Taylor community will work to reduce chronic absenteeism by 3% with families & school staff, and the Hub team actively collaborating to enhance student attendance', intervention: 'Goal: Parent attendance recognition for improved attendance', goalDate: '2026-06-26', midpoint: 'Students who have improved in attendance in May and June will receive a certificate and the parents will get a personalized letter from the prinicpals, acknowledging their effort to end the year strong', status: 'In Progress', pct: 0, endline: '' }
