    { id: 'hennigan-kpi-1', longTermGoal: 'Sense of belonging  - Increase parent and family attendance at school sponsored events by 5-10 percent during each event. Increase family engagment during each event. Events occur monthly and are advertised via ParentSquare and mailings to parents and caregivers.', intervention: 'Intervention: Send message to families one month, two weeks, one week, one day prior to the event. Remind them of the event the morning of. My Huynh- family communication', goalDate: '2026-06-30', midpoint: 'Report out after April events- February events had over 200 attendees- however only 29 families', status: 'In Progress', pct: 0, endline: '' },
    { id: 'hennigan-kpi-2', longTermGoal: 'Sense of belonging  - Increase parent and family attendance at school sponsored events by 5-10 percent during each event. Increase family engagment during each event. Events occur monthly and are advertised via ParentSquare and mailings to parents and caregivers.', intervention: 'Intervention: Mail home flyers in student back packs - one month prior to event and remind parents one week prior to the event. My Huynh0 family communication and sense of belonging. ,', goalDate: '2026-06-30', midpoint: 'Flyers have been emailed, sent via parent square, and backpacked home to all students- at least twice prior to each event. Event attendance has been high but have not hit the 50 percent benchmark set in the QSP.', status: 'In Progress', pct: 0, endline: '' },
    { id: 'hennigan-kpi-3', longTermGoal: 'Sense of belonging  - Increase parent and family attendance at school sponsored events by 5-10 percent during each event. Increase family engagment during each event. Events occur monthly and are advertised via ParentSquare and mailings to parents and caregivers.', intervention: 'Communicate with families and teachers in person during pick-ups and drop offs- reminding them of event and its goals/ intentions: HUB Coordinator, Family Liaison, Community Field Coordinator', goalDate: '2026-06-30', midpoint: 'We communicate with students, teachers, and families during pick-up and drop off. Engagement is higher for students the younger grades as compared to older students.', status: 'In Progress', pct: 0, endline: '' },
    { id: 'hennigan-kpi-4', longTermGoal: 'Sense of belonging  - Increase parent and family attendance at school sponsored events by 5-10 percent during each event. Increase family engagment during each event. Events occur monthly and are advertised via ParentSquare and mailings to parents and caregivers.', intervention: 'Provide cultural welcoming food and activities at events- with family and teacher input: My Huynh, Family Liaisons, Community Field Coordinator: Climate and Culture/ Sense of Belonging', goalDate: '2026-06-30', midpoint: 'Culturally welcoming food provided at all family events and gathering.', status: 'In Progress', pct: 0, endline: '' },
    { id: 'hennigan-kpi-5', longTermGoal: 'Sense of belonging  - Increase parent and family attendance at school sponsored events by 5-10 percent during each event. Increase family engagment during each event. Events occur monthly and are advertised via ParentSquare and mailings to parents and caregivers.', intervention: 'After events- meet as HUB team, report back on attendance, event organization, family feedback to inform the planning of upcoming events/ initiatives at the school: My Huynh, Family Liaisons, Community Field Coordinator', goalDate: '2026-06-30', midpoint: '', status: 'In Progress', pct: 0, endline: '' }
